INSERT IGNORE INTO productos (nombre, categoria, precio_kilo, stock_estimado_kg) VALUES ('Suprema', 'Pollo', 5000.00, 20), ('Milanesa de Carne', 'Vaca', 5000.00, 20), ('Milanesa de Cerdo', 'Cerdo', 5000.00, 20), ('Bife de Pollo', 'Pollo', 5000.00, 20), ('Pechuga', 'Pollo', 5000.00, 20), ('Bife de Carne', 'Vaca', 5000.00, 20), ('Chorizo', 'Cerdo', 5000.00, 20), ('Morcilla', 'Cerdo', 5000.00, 20), ('VacÀo', 'Vaca', 5000.00, 20), ('Tira de Asado', 'Vaca', 5000.00, 20), ('Lomo', 'Vaca', 5000.00, 20), ('Molida Especial', 'Vaca', 5000.00, 20), ('Molida Intermedia', 'Vaca', 5000.00, 20), ('Molida ComÈn', 'Vaca', 5000.00, 20); DELETE FROM productos WHERE nombre NOT IN ('Suprema', 'Milanesa de Carne', 'Milanesa de Cerdo', 'Bife de Pollo', 'Pechuga', 'Bife de Carne', 'Chorizo', 'Morcilla', 'VacÀo', 'Tira de Asado', 'Lomo', 'Molida Especial', 'Molida Intermedia', 'Molida ComÈn') AND id NOT IN (SELECT DISTINCT producto_id FROM detalle_ventas);  
